import scala.annotation.tailrec

/**
 * Given an integer n.
 * An integer x is called a "good integer" if there exist at least two different pairs of positive integers (a, b) satisfying the following conditions:
 * - a and b are positive integers.
 * - a <= b
 * - x = a^3 + b^3
 * Return an array containing all "good integers" less than or equal to n, sorted in ascending order.
 * 
 * Constraints: 1 <= n <= 10^9
 */
def n(N: Long): Array[Long] = {
    // We need to find all sums x = a^3 + b^3 <= N where a <= b, and count how many distinct pairs (a, b) result in the same x.

    // Since a^3 + b^3 <= N and a <= b, we must have 2*a^3 <= N, so a^3 <= N/2.
    // max_a = floor(cbrt(N/2))
    val max_a_long = Math.floor(Math.pow((N / 2.0).toDouble, 1.0/3.0)).toLong

    // The maximum value for b is determined by a=1: 1^3 + b^3 <= N, so b^3 <= N - 1.
    // max_b = floor(cbrt(N - 1))
    val max_b_long = Math.floor(Math.pow(N.toDouble, 1.0/3.0)).toLong

    // Map to store sums and the count of pairs that generate them.
    // Key: x (the sum a^3 + b^3)
    // Value: count of pairs (a, b) such that a^3 + b^3 = x and a <= b
    val sumsMap: mutable.Map[Long, Int] = mutable.Map()

    // Iterate through all possible pairs (a, b) such that 1 <= a <= b and a^3 + b^3 <= N.
    for (a <- 1 to max_a_long) {
        val aCubed = a.toLong * a.toLong * a.toLong

        // Determine the range for b. We must have b >= a.
        // Also, a^3 + b^3 <= N, so b^3 <= N - a^3.
        val upper_bound_b_cubed = N - aCubed

        // Since a >= 1, aCubed >= 1. N - aCubed <= N - 1.
        if (upper_bound_b_cubed <= 0) continue // Should not happen if max_a is calculated correctly, but safe check.

        // max_b for this 'a' is floor(cbrt(N - a^3))
        val max_b_for_a_long = Math.floor(Math.pow(upper_bound_b_cubed.toDouble, 1.0/3.0)).toLong

        // b starts from max(a, 1). Since a >= 1, b starts from a.
        val start_b = a.toLong

        for (b <- start_b to max_b_for_a_long) {
            // Calculate b^3 efficiently, though for N <= 10^9, direct multiplication is fine.
            val bCubed = b.toLong * b.toLong * b.toLong

            // Since we ensured b <= max_b_for_a_long, aCubed + bCubed <= N is guaranteed.
            val x = aCubed + bCubed

            // Since we iterate a <= b, each distinct pair (a, b) is encountered exactly once.
            sumsMap.put(x, sumsMap.getOrElse(x, 0) + 1)
        }
    }

    // Collect all sums that have a count of 2 or more.
    val goodIntegers = sumsMap
        .filter { case (_, count) => count >= 2 }
        .keys
        .toLongArray
        .sorted // The requirement asks for the result to be sorted in ascending order.

    goodIntegers
