object Solution {
  /**
    * Finds all "good numbers" less than or equal to n.
    * A number x is "good" if it can be expressed as the sum of two positive cubes,
    * x = a^3 + b^3 with a <= b, in at least two different ways.
    *
    * @param n The upper bound.
    * @return An array of long integers representing the good numbers, sorted in ascending order.
    */
  def n(n: Long): Array[Long] = {
    // Map to store sums and the pairs that generate them: Sum -> List[(a, b)]
    val sumsMap = mutable.HashMap[Long, mutable.Set[(Int, Int)]]()

    // Since a^3 + b^3 <= n, we can find an upper bound for a and b.
    // The smallest possible sum is 1^3 + 1^3 = 2.
    // If a=1, b^3 <= n - 1. b <= cbrt(n-1).
    // If a=b, 2*a^3 <= n. a^3 <= n/2. a <= cbrt(n/2).
    // We iterate 'a' up to where a^3 + a^3 <= n, which is a <= cbrt(n/2).

    // We can safely iterate 'a' up to cbrt(n). Since n <= 10^9, cbrt(n) <= 1000.
    // An integer 'a' such that a^3 <= n is sufficient for the loop boundary.
    val maxA = Math.ceil(Math.cbrt(n.toDouble)).toInt

    for (a <- 1 until (maxA + 1)) {
      val aCubed = a.toLong * a.toLong * a.toLong

      // b starts from a because a <= b
      // We need a^3 + b^3 <= n, so b^3 <= n - a^3
      val remaining = n - aCubed
      if (remaining < aCubed) {
        // Even if b=a, the sum exceeds n. We can stop iterating 'a'.
        // Since a is increasing, this condition will only get worse.
        break 
      }

      // Find max b such that b^3 <= remaining
      val maxB = Math.ceil(Math.cbrt(remaining.toDouble)).toInt

      for (b <- a until (maxB + 1)) {
        val bCubed = b.toLong * b.toLong * b.toLong
        val sum = aCubed + bCubed

        if (sum > n) {
          // Should not happen if maxB is calculated correctly, but good for safety
          break 
        }

        // Store the pair (a, b) for this sum
        sumsMap.getOrElseUpdate(sum, mutable.Set()) += ((a, b))
      }
    }

    // Collect all numbers that appeared in at least two different ways
    val goodNumbers = sumsMap.filter { case (_, pairs) => pairs.size >= 2 }
                               .keys
                               .toSeq
                               .sorted
                               .toArray
                               .map(_.toLong)

    goodNumbers
  }
}
