object Solution {
  def n(n: Long): Array[Long] = {
    // Map to store each sum (a^3 + b^3) and the set of pairs (a, b) that produce it.
    // Since we only care about the count of distinct pairs, we can just store a count or a boolean flag
    // once we find the second representation.
    val sums = mutable.HashMap[Long, Int]()

    // Determine the upper bound for a and b.
    // We need a^3 + b^3 <= n. Since a <= b, 2*a^3 <= a^3 + b^3 <= n.
    // a^3 <= n/2.
    // Since n <= 10^9, n/2 <= 5 * 10^8.
    // The cube root of 5 * 10^8 is approx 793.7.
    // Let's iterate a up to the point where a^3 is too large.

    // Maximum possible value for b occurs when a=1: b^3 <= n-1. b <= cbrt(n).
    val maxB = Math.round(Math.pow(n.toDouble, 1.0/3.0)).toLong() + 1

    // Iterate through possible values of a (a >= 1)
    var a: Long = 1
    while (true) {
      val a3 = a * a * a
      if (a3 > n) break // Optimization: if a^3 itself is > n, we stop. (This shouldn't happen if n is positive, but good safeguard)

      // Iterate through possible values of b (b >= a)
      var b: Long = a
      while (true) {
        val b3 = b * b * b
        val sum = a3 + b3

        if (sum > n) break // If the sum exceeds n, increasing b further will also exceed n.

        // The sum is valid and <= n. Count this representation.
        val currentCount = sums.getOrElse(sum, 0) + 1
        sums.put(sum, currentCount)

        // If we have found at least two pairs, we don't necessarily need to break, 
        // because we are generating all sums <= n.

        b += 1
      }
      a += 1
    }

    // Collect all sums that appeared at least twice.
    val goodNumbers = sums.keys.filter { sum => sums(sum) >= 2 }.toSeq.sorted

    // Convert to Array[Long] as required by the signature.
