object Solution {
  def n(n: Long): Array[Long] = {
    // Map to store the sum x and the number of distinct pairs (a, b) that produce it.
    // Key: sum x = a^3 + b^3
    // Value: Set of pairs (a, b) that result in x. Using a set ensures we count distinct pairs.
    // However, since we only care if the count of pairs is >= 2, we can simplify the value.
    // We'll use a mutable map where the value is a Set of pairs (a, b) to ensure we count distinct pairs.
    val sumToPairs = mutable.Map[Long, mutable.Set[(Long, Long)]]()

    // The maximum value for a or b. Since a <= b and a^3 + b^3 <= n, 
    // 2 * b^3 >= n, so b^3 >= n/2. Also, b^3 <= n, so b <= n^(1/3).
    // A safe upper bound for b is ceil(n^(1/3)). Since n <= 10^9, n^(1/3) <= 1000.
    val maxB: Int = Math.ceil(Math.pow(n.toDouble, 1.0/3.0)).toInt + 2 // Add a small buffer

    // Iterate over all possible pairs (a, b) such that 1 <= a <= b and a^3 + b^3 <= n.
    for (b <- 1 until maxB) {
      val bCubed = b.toLong * b.toLong * b.toLong
      if (bCubed > n) continue

      // Iterate a from 1 up to b
      // We need a^3 <= n - b^3
      val maxACubed = n - bCubed

      // Max a: a <= min(b, floor((n - b^3)^(1/3)))
      val maxA = Math.min(b, Math.floor(Math.pow(maxACubed.toDouble, 1.0/3.0)).toInt).toLong

      for (a <- 1 to maxA) {
        val aCubed = a * a * a
        val sum = aCubed + bCubed

        if (sum > n) break // Optimization: since a is increasing, the sum will only increase

        // Ensure a <= b condition is naturally handled by the loops setup (a <= maxA <= b)

        val pair = (a, b)

        // Update the map
        val currentPairs = sumToPairs.getOrElseUpdate(sum, mutable.Set())
        currentPairs.add(pair)
      }
    }

    // Collect all "good numbers" (sums that have at least two distinct pairs)
    val goodNumbers = mutable.ListBuffer[Long]()
    sumToPairs.foreach { case (sum, pairs) =>
      if (pairs.size >= 2) {
        goodNumbers += sum
      }
    }

    // Sort the results in ascending order
    goodNumbers.sort()

    goodNumbers.toArray
  }
